tasks.solution:
// test.js — failing version:
const assert = require('assert');
function greet(name) { return 'Hello, ' + name + '!'; }
assert.strictEqual(greet('World'), 'Hello, World!');
assert.strictEqual(greet('World'), 'Hello, CI/CD!')  // fails: actual is 'Hello, World!'
console.log('All tests passed.');

// package.json scripts section:
"scripts": {
  "start": "node index.js",
  "test": "node test.js"
}

// Jenkinsfile with Test stage:
pipeline {
    agent any
    stages {
        stage('Checkout')    { steps { checkout scm } }
        stage('Build')       { steps { sh 'npm ci' } }
        stage('Test')        { steps { sh 'npm test' } }
        stage('Build Image') { steps { sh 'echo Image build placeholder' } }
    }
}

// Push with failing test: Stage View shows Build=green, Test=RED, Build Image=skipped.
// Console Output shows AssertionError and 'Build FAILURE'.

// Fix: change the second assertion to the correct expected value:
assert.strictEqual(greet('World'), 'Hello, World!');
// Push again: all four stages turn green.

